SELECT COUNT(*) AS quantidade FROM servidor s WHERE LOWER(s.categoria) = LOWER('docente') AND LOWER(s.contrato) = LOWER('efetivos') AND LOWER(s.area_ingresso) LIKE LOWER('%enfermagem%') AND LOWER(s.sigla_campus) = LOWER('lin') AND s.saiu_do_ifg = FALSE AND (SELECT 1 FROM calc_hora_aula_media c WHERE c.siape = s.pk_siape AND c.ano = 2023 AND c.semestre = 1 LIMIT 1) IS NOT NULL